import { useState, useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { PageShell } from "@/components/orderly/PageShell";
import { SectionCard } from "@/components/orderly/SectionCard";
import { DexUpgradeNotice } from "@/components/orderly/DexUpgradeNotice";
import { Modal } from "@/components/orderly/Modal";
import {
  Rocket,
  Settings,
  ArrowRight,
  Globe,
  Loader2,
  AlertTriangle,
  Trash2,
} from "lucide-react";
import { useTranslation } from "@/i18n";
import { LocalizedLink } from "@/utils/localizedRoute";
import { toast } from "@/hooks/use-toast";
import {
  fetchDexCreatorDexStatus,
  createDexCreatorFrontend,
  deleteDexCreatorFrontend,
} from "@/services/orderly";
import { getProfile } from "@/utils/branding-shared";
import { walletSetItem } from "@/utils/storage";

type CreationState = "idle" | "creating" | "success" | "error";

export default function FrontendSetupPage() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const [repoUrl, setRepoUrl] = useState<string | null>(null);
  const [frontendAvailable, setFrontendAvailable] = useState(false);
  const [creationState, setCreationState] = useState<CreationState>("idle");
  const [errorMessage, setErrorMessage] = useState("");
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteConfirmText, setDeleteConfirmText] = useState("");
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    const p = getProfile();
    const localHasFrontend =
      Boolean(p?.repoUrl) ||
      p?.pathway === "low-code" ||
      p?.integrationType === "low_code";

    if (p?.repoUrl) setRepoUrl(p.repoUrl);
    setFrontendAvailable(localHasFrontend);

    fetchDexCreatorDexStatus({ force: true }).then(status => {
      if (status && status.exists !== false) {
        const statusHasFrontend =
          Boolean(status.repoUrl) || status.integrationType === "low_code";
        setRepoUrl(
          status.repoUrl || (statusHasFrontend ? p?.repoUrl || null : null)
        );
        setFrontendAvailable(statusHasFrontend);
      }
    });
  }, []);

  const hasFrontend = frontendAvailable || Boolean(repoUrl);

  const handleCreateFrontend = useCallback(async () => {
    const p = getProfile();
    if (!p?.dexId) return;

    setCreationState("creating");
    setErrorMessage("");

    try {
      const formData = new FormData();
      if (p.builderName) formData.append("brokerName", p.builderName);

      const result = await createDexCreatorFrontend(p.dexId, formData);
      setRepoUrl(result.repoUrl || null);
      setFrontendAvailable(true);
      setCreationState("success");

      const updatedProfile = {
        ...p,
        repoUrl: result.repoUrl,
        dexConfigured: true,
        integrationType: "low_code",
        pathway: "low-code" as const,
      };
      walletSetItem("orderlyProfile", JSON.stringify(updatedProfile));
      window.dispatchEvent(new CustomEvent("profileUpdated"));

      setTimeout(() => navigate("/dex-config"), 2000);
    } catch (err) {
      setCreationState("error");
      setErrorMessage(
        err instanceof Error ? err.message : "Failed to create DEX frontend"
      );
    }
  }, [navigate]);

  const handleDeleteFrontend = useCallback(async () => {
    const p = getProfile();
    if (!p?.dexId) return;

    setDeleting(true);
    try {
      await deleteDexCreatorFrontend(p.dexId);
      setRepoUrl(null);
      setFrontendAvailable(false);

      const updatedProfile = {
        ...p,
        repoUrl: null,
        dexConfigured: false,
        integrationType: "custom",
        pathway: "sdk" as const,
      };
      walletSetItem("orderlyProfile", JSON.stringify(updatedProfile));
      setShowDeleteConfirm(false);
      setDeleteConfirmText("");
      window.dispatchEvent(new CustomEvent("profileUpdated"));
    } catch (err) {
      toast({
        title:
          err instanceof Error ? err.message : "Failed to delete DEX frontend",
        variant: "destructive",
      });
    } finally {
      setDeleting(false);
    }
  }, []);

  if (!hasFrontend && creationState !== "success") {
    return (
      <PageShell pageTitle="Frontend setup">
        <div className="flex flex-col items-center justify-center rounded-xl border border-dashed border-(--line-subtle) bg-(--bg-surface-secondary) p-10 text-center">
          <div className="mb-4 flex h-14 w-14 items-center justify-center rounded-full bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
            <Rocket className="h-6 w-6" />
          </div>
          <h4 className="mb-1 text-base font-medium text-(--fg-primary)">
            Create your DEX frontend
          </h4>
          <p className="mb-5 max-w-sm text-[15px] leading-6 text-(--fg-secondary)">
            This will create a hosted DEX frontend from our template. You can
            customize branding, themes, and settings after creation.
          </p>

          {creationState === "error" && (
            <div className="mb-5 w-full max-w-sm rounded-lg border border-red-500/30 bg-red-500/10 p-3 text-sm text-red-400">
              {errorMessage}
            </div>
          )}

          <button
            type="button"
            onClick={handleCreateFrontend}
            disabled={creationState === "creating"}
            className="inline-flex items-center gap-2 rounded-full px-5 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
            style={{ background: "var(--bg-brand-grad)" }}
          >
            {creationState === "creating" ? (
              <>
                <Loader2 className="h-4 w-4 animate-spin" />
                Creating frontend...
              </>
            ) : (
              <>
                <Rocket className="h-4 w-4" />
                Create
              </>
            )}
          </button>

          <p className="mt-4 max-w-sm text-[10px] leading-4 text-(--fg-secondary)">
            You can further configure branding, themes, and settings after
            creation.
          </p>
        </div>
      </PageShell>
    );
  }

  if (creationState === "success") {
    return (
      <PageShell pageTitle="Frontend setup">
        <div className="space-y-6">
          <SectionCard>
            <div className="flex flex-col items-center gap-4 py-8">
              <div className="flex h-16 w-16 items-center justify-center rounded-full bg-[rgba(29,246,181,0.12)] text-[#1DF6B5]">
                <Rocket className="h-8 w-8" />
              </div>
              <h2 className="text-lg font-medium text-(--fg-primary)">
                DEX frontend created!
              </h2>
              <p className="text-sm text-(--fg-secondary)">
                Redirecting to configuration...
              </p>
            </div>
          </SectionCard>
        </div>
      </PageShell>
    );
  }

  return (
    <PageShell pageTitle="Frontend setup">
      <div className="space-y-6">
        <DexUpgradeNotice />

        <SectionCard>
          <div className="mb-5 flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
            <div>
              <h2 className="text-lg font-medium text-(--fg-primary)">
                Manage your DEX frontend
              </h2>
              <p className="mt-1 text-sm text-(--fg-secondary)">
                Configure your DEX frontend deployment status or customise your
                settings.
              </p>
            </div>
            <button
              type="button"
              onClick={() => {
                setDeleteConfirmText("");
                setShowDeleteConfirm(true);
              }}
              className="inline-flex shrink-0 items-center justify-center gap-1.5 rounded-full px-3 py-1.5 text-xs font-medium text-[var(--fg-negative)] transition-colors hover:bg-[var(--bg-negative-subtle)]"
            >
              <Trash2 className="h-3.5 w-3.5" />
              {t("frontendSetup.deleteFrontend")}
            </button>
          </div>

          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <LocalizedLink
              to="/dex-config"
              className="group flex flex-col gap-3 rounded-xl border border-(--bg-hover) bg-(--bg-surface-secondary) p-5 transition-all hover:bg-(--bg-hover)"
            >
              <div className="flex items-center justify-between">
                <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
                  <Settings className="h-5 w-5" />
                </div>
                <ArrowRight className="h-5 w-5 text-(--fg-secondary) transition-colors group-hover:text-(--fg-brand)" />
              </div>
              <div>
                <h3 className="text-base font-medium text-(--fg-primary)">
                  Frontend configuration
                </h3>
                <p className="mt-0.5 text-sm text-(--fg-secondary)">
                  Customise branding, themes, social links, and more.
                </p>
              </div>
            </LocalizedLink>

            <LocalizedLink
              to="/deployment-status"
              className="group flex flex-col gap-3 rounded-xl border border-(--bg-hover) bg-(--bg-surface-secondary) p-5 transition-all hover:bg-(--bg-hover)"
            >
              <div className="flex items-center justify-between">
                <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
                  <Rocket className="h-5 w-5" />
                </div>
                <ArrowRight className="h-5 w-5 text-(--fg-secondary) transition-colors group-hover:text-(--fg-brand)" />
              </div>
              <div>
                <h3 className="text-base font-medium text-(--fg-primary)">
                  Deployment status
                </h3>
                <p className="mt-0.5 text-sm text-(--fg-secondary)">
                  View your DEX frontend deployment status and domain
                  configuration.
                </p>
              </div>
            </LocalizedLink>

            <LocalizedLink
              to="/custom-domain"
              className="group flex flex-col gap-3 rounded-xl border border-(--bg-hover) bg-(--bg-surface-secondary) p-5 transition-all hover:bg-(--bg-hover)"
            >
              <div className="flex items-center justify-between">
                <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
                  <Globe className="h-5 w-5" />
                </div>
                <ArrowRight className="h-5 w-5 text-(--fg-secondary) transition-colors group-hover:text-(--fg-brand)" />
              </div>
              <div>
                <h3 className="text-base font-medium text-(--fg-primary)">
                  {t("navigation.customDomain")}
                </h3>
                <p className="mt-0.5 text-sm text-(--fg-secondary)">
                  {t("customDomain.configureBrandedDomain")}
                </p>
              </div>
            </LocalizedLink>
          </div>
        </SectionCard>
      </div>

      <Modal
        open={showDeleteConfirm}
        onClose={() => {
          if (!deleting) setShowDeleteConfirm(false);
        }}
        title={t("frontendSetup.deleteFrontend")}
      >
        <div className="space-y-5">
          <div className="flex items-start gap-3 rounded-lg border border-[rgba(255,99,144,0.25)] bg-[rgba(255,99,144,0.08)] px-3 py-2.5 text-sm text-[#FF6390]">
            <AlertTriangle className="mt-0.5 h-4 w-4 shrink-0" />
            <span>{t("frontendSetup.deleteFrontendWarning")}</span>
          </div>
          <label className="block">
            <span className="mb-2 block text-sm font-medium text-(--fg-primary)">
              {t("frontendSetup.deleteFrontendConfirm")}
            </span>
            <input
              type="text"
              value={deleteConfirmText}
              onChange={e => setDeleteConfirmText(e.target.value)}
              className="h-11 w-full rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-3 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
              placeholder="DELETE"
              autoComplete="off"
            />
          </label>
          <div className="flex justify-end gap-3">
            <button
              type="button"
              disabled={deleting}
              onClick={() => setShowDeleteConfirm(false)}
              className="inline-flex h-10 items-center justify-center rounded-full border border-(--line-subtle) px-4 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover) disabled:cursor-not-allowed disabled:opacity-50"
            >
              {t("common.cancel")}
            </button>
            <button
              type="button"
              disabled={deleting || deleteConfirmText !== "DELETE"}
              onClick={() => void handleDeleteFrontend()}
              className="inline-flex h-10 items-center justify-center rounded-full bg-[#FF6390] px-5 text-sm font-semibold text-white transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
            >
              {deleting
                ? t("common.saving")
                : t("frontendSetup.deleteFrontend")}
            </button>
          </div>
        </div>
      </Modal>
    </PageShell>
  );
}
